// Validate and normalize the incoming research request
const body = $input.first().json.body || $input.first().json;

if (!body.query || body.query.trim().length < 3) {
  throw new Error('Invalid query: must be at least 3 characters');
}

const normalized = {
  query: body.query.trim(),
  search_depth: body.search_depth || 'advanced',
  use_cache: body.use_cache !== false,
  notify_n8n: false,  // Avoid loop: don't re-notify n8n from pipeline
  metadata: {
    source: body.metadata?.source || 'n8n',
    user_id: body.metadata?.user_id || 'anonymous',
    timestamp: new Date().toISOString()
  }
};

return [{ json: normalized }];

// Format the research report into a clean output document
const report = $input.first().json;

const verdict = report.fact_check?.verdict || 'UNKNOWN';
const confidence = Math.round((report.overall_confidence || 0) * 100);

const sourceList = (report.sources || [])
  .slice(0, 5)
  .map((s, i) => `${i + 1}. [${s.title}](${s.url}) — Score: ${(s.score * 100).toFixed(0)}%`)
  .join('\n');

const keyPoints = (report.summary?.key_points || [])
  .map((p, i) => `• ${p}`)
  .join('\n');

const formatted = {
  // Metadata
  query: report.query,
  generated_at: report.completed_at,
  latency_seconds: Math.round(report.total_latency_ms / 1000),
  overall_confidence_pct: confidence,
  verdict: verdict,
  verdict_emoji: report.fact_check?.verdict_emoji || '❓',

  // Formatted text sections
  executive_summary: report.summary?.summary || 'No summary available.',
  key_findings: keyPoints,
  top_sources: sourceList,
  fact_check_assessment: report.fact_check?.fact_check_summary || '',

  // Structured data
  key_entities: report.summary?.key_entities || {},
  contradictions: report.fact_check?.contradictions || [],
  unverified_claims: report.fact_check?.unverified_claims || [],

  // Full report passthrough
  _raw: report
};

return [{ json: formatted }];

// Generate a Markdown-formatted report document
const r = $input.first().json;

const md = `# Research Report

**Query:** ${r.query}
**Generated:** ${r.generated_at}
**Confidence:** ${r.overall_confidence_pct}% ${r.verdict_emoji}
**Verdict:** ${r.verdict}
**Pipeline Time:** ${r.latency_seconds}s

---

## Executive Summary

${r.executive_summary}

## Key Findings

${r.key_findings}

## Sources

${r.top_sources}

## Fact-Check Assessment

${r.fact_check_assessment || '_No fact-check data available._'}

${r.contradictions.length > 0 ? '## ⚠️ Contradictions Found\n\n' + r.contradictions.map(c => '- ' + c).join('\n') : ''}

---
*Generated by Multi-Agent Research Assistant*
`;

return [{ json: { ...r, markdown_report: md } }];

const report = $input.first().json;
const errors = report.errors || [];

return [{
  json: {
    error: true,
    status: report.status || 'failed',
    query: report.query,
    errors: errors,
    message: errors.length > 0 ? errors.join('; ') : 'Pipeline returned partial results',
    partial_data: {
      sources_count: (report.sources || []).length,
      has_summary: !!report.summary,
      has_fact_check: !!report.fact_check
    }
  }
}];
